import type React from 'react';
import type { TestComponentProps } from '../../types/test-component';
/**
 * Тип контента для Open Graph
 */
export type OpenGraphType = 'website' | 'article' | 'product' | 'profile' | 'book' | 'music' | 'video';
/**
 * Тип карточки Twitter
 */
export type TwitterCardType = 'summary' | 'summary_large_image' | 'app' | 'player';
/**
 * Директивы для поисковых роботов
 */
export type RobotsDirective = 'index' | 'noindex' | 'follow' | 'nofollow' | 'noarchive' | 'nosnippet';
/**
 * Базовый интерфейс для SEO метаданных
 * Используется как для компонента SEOHead, так и для функции generateMetadata
 */
export interface SEOHeadBaseProps {
    /**
     * Заголовок страницы (обязательный)
     * Отображается в поиске и вкладке браузера
     * Рекомендуемая длина: до 60 символов
     */
    title: string;
    /**
     * Описание страницы (обязательное)
     * Может использоваться как сниппет в поиске
     * Рекомендуемая длина: до 160 символов
     */
    description: string;
    /**
     * Канонический URL страницы (обязательный)
     * Должен быть полным URL с https://
     * Используется для предотвращения дублей контента
     */
    canonicalUrl: string;
    /**
     * Язык документа
     * @default 'ru'
     */
    lang?: string;
    /**
     * Директивы для поисковых роботов
     * @default 'index, follow'
     */
    robots?: string | RobotsDirective[];
    /**
     * Заголовок для Open Graph (социальные сети)
     * Если не указан, используется title
     */
    ogTitle?: string;
    /**
     * Описание для Open Graph
     * Если не указано, используется description
     */
    ogDescription?: string;
    /**
     * Тип контента для Open Graph
     * @default 'website'
     */
    ogType?: OpenGraphType;
    /**
     * URL для Open Graph
     * Если не указан, используется canonicalUrl
     */
    ogUrl?: string;
    /**
     * URL изображения для Open Graph превью
     * Рекомендуемый размер: 1200×630 px
     * Формат: JPG/PNG
     */
    ogImage?: string;
    /**
     * Тип карточки Twitter
     * @default 'summary_large_image'
     */
    twitterCard?: TwitterCardType;
    /**
     * Путь к favicon
     * @default '/favicon.ico'
     */
    favicon?: string;
    /**
     * Путь к Apple Touch Icon
     * Размер: 180×180 px
     */
    appleTouchIcon?: string;
    /**
     * Кодировка документа
     * @default 'UTF-8'
     */
    charset?: string;
    /**
     * Viewport meta тег
     * @default 'width=device-width, initial-scale=1.0'
     */
    viewport?: string;
}
/**
 * Пропсы компонента SEOHead
 * Расширяет базовый интерфейс для использования в React компоненте
 */
export interface SEOHeadProps extends SEOHeadBaseProps, TestComponentProps {
    /**
     * Дополнительные теги для head
     * Можно передать массив React элементов для кастомных тегов
     */
    children?: React.ReactNode;
}
